import{_ as e,o as a,c as i,a3 as r}from"./chunks/framework.LBeL10WQ.js";const m=JSON.parse('{"title":"Social Ads","description":"","frontmatter":{"title":"Social Ads"},"headers":[],"relativePath":"advertisers/sponsored-social/index.md","filePath":"advertisers/sponsored-social/index.md"}'),s={name:"advertisers/sponsored-social/index.md"};function o(n,t,l,d,c,u){return a(),i("div",null,[...t[0]||(t[0]=[r('<h1 id="social-ads-partnership-ads" tabindex="-1">Social Ads (Partnership Ads) <a class="header-anchor" href="#social-ads-partnership-ads" aria-label="Permalink to &quot;Social Ads (Partnership Ads)&quot;">​</a></h1><p>Diffusez vos publicités via les comptes Instagram, TikTok et Facebook de nos e-commerçants partenaires — en tirant parti de leur crédibilité auprès de leur communauté.</p><div class="info custom-block"><p class="custom-block-title">Format sur demande</p><p>Ce format est disponible en contactant notre équipe : <a href="mailto:studio@getinside.fr" target="_blank" rel="noreferrer">studio@getinside.fr</a></p></div><hr><h2 id="comment-ca-marche" tabindex="-1">Comment ça marche ? <a class="header-anchor" href="#comment-ca-marche" aria-label="Permalink to &quot;Comment ça marche ?&quot;">​</a></h2><p>Plutôt que de diffuser une publicité classique depuis votre compte, vous sponsorisez un post publié depuis le compte du distributeur (<strong>Partnership Ads</strong> sur Meta, <strong>Spark Ads</strong> sur TikTok). Le distributeur y appose la mention obligatoire <em>&quot;Partenariat rémunéré&quot;</em>.</p><p><strong>Le workflow en 4 étapes :</strong></p><ol><li><strong>Brief &amp; Sélection</strong> — Choisissez le distributeur partenaire et transmettez l&#39;angle créatif, les visuels et les messages clés.</li><li><strong>Création</strong> — Vous fournissez le contenu prêt à poster, ou le distributeur / Studio getinside le crée pour un rendu natif.</li><li><strong>Publication</strong> — Le distributeur publie avec la mention <em>&quot;Partenariat rémunéré&quot;</em> et active les droits d&#39;amplification.</li><li><strong>Amplification</strong> — getinside active la campagne Ads sur le post pour toucher une audience large (abonnés + Lookalike).</li></ol><hr><h2 id="formats-specifications" tabindex="-1">Formats &amp; Spécifications <a class="header-anchor" href="#formats-specifications" aria-label="Permalink to &quot;Formats &amp; Spécifications&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Format</th><th style="text-align:left;">Dimensions</th><th style="text-align:left;">Recommandation</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Vidéo</strong> (Reels/TikTok)</td><td style="text-align:left;">9:16 — 1080 × 1920 px, 15–60 s</td><td style="text-align:left;">Recommandé — zone de sûreté 15% haut/bas</td></tr><tr><td style="text-align:left;"><strong>Image Feed</strong></td><td style="text-align:left;">4:5 — 1080 × 1350 px</td><td style="text-align:left;">Texte ≤ 20% de la surface</td></tr><tr><td style="text-align:left;"><strong>Story</strong></td><td style="text-align:left;">9:16 — 1080 × 1920 px, 15 s/slide</td><td style="text-align:left;">Prévoir espace pour le sticker lien</td></tr></tbody></table><hr><h2 id="tarification" tabindex="-1">Tarification <a class="header-anchor" href="#tarification" aria-label="Permalink to &quot;Tarification&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Poste</th><th style="text-align:left;">Coût</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Frais de plateforme</strong></td><td style="text-align:left;">12% du budget média investi</td></tr><tr><td style="text-align:left;"><strong>Studio Créatif</strong> (optionnel)</td><td style="text-align:left;">Forfait 550€ HT par création</td></tr></tbody></table>',14)])])}const f=e(s,[["render",o]]);export{m as __pageData,f as default};
